Rules.InvariantScript:
Set(varInputText, Lower(txtProblem.Text & " " & txtBusinessImpact.Text & " " & txtAdditionalInfo.Text));
Set(varCategory, If(IsBlank(Trim(txtProblem.Text)), "Needs problem statement", If(Or("login" in varInputText, "access" in varInputText, "permission" in varInputText, "role" in varInputText), "Access / permissions", If(Or("bug" in varInputText, "error" in varInputText, "broken" in varInputText, "fail" in varInputText), "Bug / defect", If(Or("report" in varInputText, "dashboard" in varInputText, "data" in varInputText), "Reporting / data", If(Or("automation" in varInputText, "workflow" in varInputText, "approval" in varInputText), "Automation / workflow", "Enhancement / discovery"))))));
Set(varEffort, If(IsBlank(Trim(txtProblem.Text)), "", If(Or("outage" in varInputText, "blocked" in varInputText, "urgent" in varInputText, "security" in varInputText), "Large / urgent triage", If(Len(varInputText) > 450, "Medium: 3-5 days", "Small: 1-2 days"))));
Set(varTimeline, If(IsBlank(Trim(txtProblem.Text)), "", If(Or("urgent" in varInputText, "outage" in varInputText, "blocked" in varInputText), "Start today", If(Len(varInputText) > 450, "This sprint after discovery", "Next available triage slot"))));
Set(varQuestion, If(IsBlank(Trim(txtProblem.Text)), "Start by describing the problem in one or two sentences.", "Follow-up: who is affected, what happens today, and what would a good result look like?"));
Set(varDeveloperNotes, If(IsBlank(Trim(txtProblem.Text)), "Ask the requester for the core problem, affected users, business impact, and desired outcome before triage.", "Developer notes: confirm affected users, repro steps, priority, target system, desired outcome, and deadline. Signals found: " & varCategory & "; " & varEffort & "; " & varTimeline & ". Extra context: " & txtAdditionalInfo.Text));
Reset(txtCategory);
Reset(txtEffort);
Reset(txtTimeline);
Reset(txtDeveloperNotes)

Set(varCategory, "");
Set(varEffort, "");
Set(varTimeline, "");
Set(varQuestion, "");
Set(varDeveloperNotes, "");
Set(varRequestTitle, "");
Set(varProblemDescription, "");
Set(varBusinessImpact, "");
Reset(txtRequestTitle);
Reset(txtProblem);
Reset(txtBusinessImpact);
Reset(txtAdditionalInfo);
Reset(txtCategory);
Reset(txtEffort);
Reset(txtTimeline);
Reset(txtDeveloperNotes)

If(IsBlank(Trim(txtAgentMessage.Text)),
    Notify("Type a message for the intake agent first.", NotificationType.Warning),
    Set(varChatText, Trim(txtAgentMessage.Text));
    Set(
        varAgentResponse,
        IntakeCopilot_CanvasRun.Run(
            varChatText,
            JSON(
                {
                    title: Coalesce(txtRequestTitle.Text, varRequestTitle, ""),
                    description: Coalesce(txtProblem.Text, varProblemDescription, ""),
                    category: Coalesce(varCategory, "Uncategorized"),
                    businessImpact: Coalesce(txtBusinessImpact.Text, varBusinessImpact, ""),
                    estimatedEffort: Coalesce(varEffort, ""),
                    estimatedDuration: Coalesce(varTimeline, ""),
                    additionalInformation: Coalesce(txtAdditionalInfo.Text, "")
                },
                JSONFormat.Compact
            ),
            JSON(
                Table(
                    {
                        role: "context",
                        content: Coalesce(varConversationLog, ""),
                        createdAt: Text(Now(), DateTimeFormat.UTC)
                    },
                    {
                        role: "user",
                        content: varChatText,
                        createdAt: Text(Now(), DateTimeFormat.UTC)
                    }
                ),
                JSONFormat.Compact
            )
        )
    );
    IfError(
        Set(varParsedDraft, ParseJSON(varAgentResponse.response));
        Set(varRequestTitle, If(IsBlank(Text(varParsedDraft.title)), txtRequestTitle.Text, Text(varParsedDraft.title)));
        Set(varProblemDescription, If(IsBlank(Text(varParsedDraft.description)), txtProblem.Text, Text(varParsedDraft.description)));
        Set(varBusinessImpact, If(IsBlank(Text(varParsedDraft.businessImpact)), txtBusinessImpact.Text, Text(varParsedDraft.businessImpact)));
        Set(varCategory, Coalesce(Text(varParsedDraft.category), "Uncategorized"));
        Set(varEffort, Coalesce(Text(varParsedDraft.estimatedEffort), ""));
        Set(varTimeline, Coalesce(Text(varParsedDraft.estimatedDuration), ""));
        Set(varQuestion, Coalesce(Text(varParsedDraft.nextQuestion), "I captured the latest message. Review the auto-filled fields and save the draft."));
        Set(varDeveloperNotes, "Developer notes: " & Coalesce(Text(varParsedDraft.additionalInformation), ""));
        Set(varConversationLog, Coalesce(varConversationLog, "Agent: Tell me what the requester needs. I will ask follow-up questions and fill the intake fields as we go.") & Char(10) & Char(10) & "You: " & varChatText & Char(10) & "Agent: " & varQuestion),
        Notify("The intake agent did not return a usable response. Please try again.", NotificationType.Error)
    );
    Reset(txtRequestTitle);
    Reset(txtProblem);
    Reset(txtBusinessImpact);
    Reset(txtCategory);
    Reset(txtEffort);
    Reset(txtTimeline);
    Reset(txtDeveloperNotes);
    Reset(txtAgentTranscript);
    Reset(txtAgentMessage)
)
